import {Clock, Time, THREE} from "animation-utilities";
import { Event, EventContainer } from 'jibo-typed-events';
import {SpeakerIdConfidence, SpeakerIdStatus} from "./GlobalListenTypes";


/**
 * @class PositionInSpace
 * @memberof jibo.lps
 * @description 3D point in space.
 * @param {number} [x=0] Meters forward.
 * @param {number} [y=0] Meters left.
 * @param {number} [z=0] Meters up.
 */
export class PositionInSpace {
    x: number;
    y: number;
    z: number;
    confidence: number;
    constructor(x:number=0, y:number=0, z:number=0) {
        this.x = x;
        this.y = y;
        this.z = z;
    }
}

/**
 * @typedef jibo.lps#IDSummary
 * @description Summary of attributes an entity identified by LPS
 * @prop {String} name Best available estimate of identity. May be `UNKNOWN` because LPS does not know or `NOT_TRAINED` if not in loop.
 * @prop {jibo.lps.identity#SensoryType} kind Usually the primary kind of identification like `face` or `voice` or `fused`.
 * @prop {Number} confidence `[0,1]` confidence in the summary identification.
 * @prop {any} ts Timestamp of when summary last updated.
 */
export interface IDSummary {
    name: string;
    kind: SensoryType;
    confidence: number;
    ts: any;
}

/**
 * @typedef jibo.lps#LPSEntity
 * @description All attributes of incoming entities from LPS Service.
 * @prop {string} id UUID of LPS system mapping to entity, including looper ID if recognized.
 * @prop {number} confidence Confidence in the information about the entity.
 * @prop {jibo.lps.identity#SensoryType} description Description of the entity.
 * @prop {string} extent Length of the object in each axis.
 * @prop {jibo.lps#IDSummary} id_summary Summary of attributes of entity.
 * @prop {string} identity_inputs Map of Identity hypotheses from multiple sources.
 * @prop {boolean} in_fov  Is Entity in the FOV / frustrum of cameras.
 * @prop {boolean} was_in_fov  Was Entity in the FOV / frustrum of cameras in last poll.
 * @prop {jibo.animate.Time} last_measured Timestamp of when entity was last measured.
 * @prop {boolean} occluded Set when occluded by other entity.
 * @prop {jibo.lps.PositionInSpace} orientation Rotation about each axis in radians.
 * @prop {string} parts Parts that compose the entity.
 * @prop {jibo.lps.PositionInSpace} position Position in world space.
 * @prop {boolean} static Whether the item is static or not.
 * @prop {string} tags Open set of tags for this entity used for things like emotional state, etc.
 * @prop {string} velocity Velocity that the entity is moving.
 */
export interface LPSEntity{
    confidence: number;
    description: SensoryType;
    extent: string;
    id: string;
    id_summary: IDSummary;
    identity_inputs: string;
    in_fov: boolean;
    was_in_fov: boolean;
    last_measured: Time;
    occluded: boolean;
    orientation: PositionInSpace;
    parts: string;
    position: PositionInSpace;
    static: boolean;
    tags: string;
    velocity: string;
}

/**
 * @interface jibo.lps#AudioLPSEntity
 * @description Describes the AudioAwareness entity in the `/audio_awareness` stream.
 * @prop {number[]} ts Timestamp in [number, number] form of value data.
 * @prop {number} id UUID of LPS system mapping to entity, including looper ID if recognized.
 * @prop {jibo.lps#AudioLPSEntityType} type Type of audio entity.
 * @prop {jibo.lps.ConfidencePosition[]} alternates A list of alternate positions in world space.
 */
export interface AudioLPSEntity extends ConfidencePosition {
    ts: [number, number];
    id: number;
    type: AudioLPSEntityType;
    // Note this should be "position" but service currently uses "location"
    alternates: ConfidencePosition[];
}

/**
 * @typedef jibo.lps#AudioLPSEntityType
 * @description Enum of audio LPS entities
 * @prop ENERGY = 0 Audio energy data.
 * @prop HOT_WORD = 1 HJ Hotphrase data.
 * @prop SPEAKER_ID = 2 Speaker ID data.
 */
export type AudioLPSEntityType = 0 | 1 | 2;
export namespace AudioLPSEntityType {
    export const ENERGY: AudioLPSEntityType = 0;
    export const HOT_WORD: AudioLPSEntityType = 1;
    export const SPEAKER_ID: AudioLPSEntityType = 2;
}

/**
 * @typedef jibo.lps#Sector
 * @description All attributes of incoming sectors from LPS Service.
 * @prop {jibo.lps#TSValuePair} activity General activity level of this sector [0,1] where 0 is low activity, 1 is high activity
 * @prop {Object} arc The arc in range [0,2*PI] that this sector represents
 * @prop {jibo.lps#TSValuePair} audioLevel Audio level measurement of this sector [0,1] where 0 is low audio, 1 is high audio
 * @prop {jibo.lps#TSValuePair} lightingLevel Average luminance in this sector [0,inf] where 0 is low luminance, 1 is high luminance. See above graph to map to approximate lux measurements
 * @prop {jibo.lps#TSValuePair} lightingQuality Average lighting quality in this sector [0,1] where 0 is poor quality, 1 is high quality. This is based off of the lighting level and what we believe to be good and bad values for vision (and photos)
 * @prop {number} id Unique ID of the sector, also the index in the list
 * @prop {jibo.lps#TSValuePair} visibility Fraction of sector in FOV. 0.0 means not in FOV 1.0 is completely, in between is partial.
 */
export interface Sector{
    activity: TSValuePair;
    arc: {Object};
    audioLevel: TSValuePair;
    lightingLevel: TSValuePair;
    lightingQuality: TSValuePair;
    id: number;
    visibility: TSValuePair;
}

/**
 * @typedef jibo.lps#TSValuePair
 * @description A common format for value data from LPS Service.
 * @prop {number[]} ts Timestamp in [number, number] form of value data.
 * @prop {number} value The value of the data given.
 */
export interface TSValuePair {
    ts: Array<number>;
    value: number;
}

/**
 * @typedef jibo.lps#JiboBodyAxis
 * @description Enum of Jibo's body axis
 * @prop PELVIS Bottom body axis name.
 * @prop TORSO Mid body axis name.
 * @prop NECK Upper body axis name.
 */
export type JiboBodyAxis = 'PELVIS' | 'TORSO' | 'NECK';
export namespace JiboBodyAxis {
    export const PELVIS: JiboBodyAxis = 'PELVIS';
    export const TORSO: JiboBodyAxis = 'TORSO';
    export const NECK: JiboBodyAxis = 'NECK';
}

/**
 * @interface jibo.lps.identity#Person
 * @description Interface of elements of a recognized Person Entity
 * @prop {String} id UUID of LPS system mapping to entity, including looper ID if recognized.
 * @prop {jibo.lps.identity#SensoryType | jibo.lps.identity#IDLabels} type Type of entity recognized.
 */
export interface Person{
    id: string;
    type: SensoryType | IDLabels;
}

// Todd might have these separately
/**
 * @typedef jibo.lps.identity#IDLabels
 * @description Possible ID status labels for entities.
 * @prop NOT_ENROLLED Speaker is definitely not enrolled.
 * @prop ANYBODY Speaker could or could not be enrolled.
 * @prop IDENTIFIED Speaker is in the loop and identified.
 * @prop UNKONWN The entity identification is not known.
 * @prop NOT_TRAINED The entity is definitely not trained.
 */
export type IDLabels = 'NOT_ENROLLED' | 'ANYBODY' | 'IDENTIFIED' | 'UNKNOWN' | 'NOT_TRAINED';
export namespace IDLabels {
    export const NOT_ENROLLED: IDLabels = 'NOT_ENROLLED';
    export const ANYBODY: IDLabels = 'ANYBODY';
    export const IDENTIFIED: IDLabels = 'IDENTIFIED';
    export const UNKNOWN: IDLabels = 'UNKNOWN';
    export const NOT_TRAINED: IDLabels = 'NOT_TRAINED';
}

/**
 * @typedef jibo.lps.identity#SensoryType
 * @description Possible sensory types.
 * @prop AUDIO_LOCALIZATION Audio Input
 * @prop MOTION Motion input
 * @prop VISION Visual Input
 * @prop WAKE Any input that woke Jibo
 * @prop VOICE Voice input
 * @prop GROUND_TRUTH Ground truth input to LPS
 */
export type SensoryType = 'AUDIO_LOCALIZATION' | 'MOTION' | 'PERSON' | 'WAKE' | 'VOICE' | 'GROUND_TRUTH';
export namespace SensoryType {
    export const AUDIO_LOCALIZATION: SensoryType = 'AUDIO_LOCALIZATION';
    export const MOTION: SensoryType = 'MOTION';
    export const PERSON: SensoryType = 'PERSON';
    export const WAKE: SensoryType = 'WAKE';
    export const VOICE: SensoryType = 'VOICE';
    export const GROUND_TRUTH: SensoryType = 'GROUND_TRUTH';

    export function fromString(name: string): SensoryType {
        return SensoryType[name] || SensoryType[name.toUpperCase()];
    }
}

/**
 * @description
 * Record of any type of sensory input.
 * @memberof jibo.lps.identity
 * @class SensoryRecord
 * @param entity {jibo.lps#LPSEntity} Attributes of incoming entities from the LPS Service.
 * @param position {object} Position in space.
 * @param type {jibo.lps.identity#SensoryType} Type of sensory recognition (`voice` or `face`).
 * @param reportedTS {jibo.animate.Time} The jibo TS at which it was reported.
 */
export class SensoryRecord{

    /**
     * @description Type of sensory recognition (`voice` or `face`).
     * @name jibo.lps.identity.SensoryRecord#type
     * @type jibo.lps.identity#SensoryType
     */
    public type:SensoryType;

    /**
     * @description Position in space.
     * @name jibo.lps.identity.SensoryRecord#position
     * @type Object
     * @default null
     */
    public position:any = null;

    /**
     * @description Raw LPS WS data.
     * @name jibo.lps.identity.SensoryRecord#raw
     * @type Object
     */
    public raw:any;

    /**
     * @description Time this data was received.
     * @name jibo.lps.identity.SensoryRecord#receivedAt
     * @type jibo.animate.Time
     */
    public receivedAt:Time;

    /**
     * @description The jibo TS at which it was reported.
     * @name jibo.lps.identity.SensoryRecord#reportedTS
     * @type jibo.animate.Time
     */
    public reportedTS:Time;

    /**
     * @description ID of sensory record as provided from LPS Service.
     * @name jibo.lps.identity.SensoryRecord#id
     * @type Object
     */
    public id:any;

    /**
     * @description Confidence in our recognition.
     * @name jibo.lps.identity.SensoryRecord#confidence
     * @type number
     */
    public confidence:number;

    /**
     * @description Timestamp of last update.
     * @name jibo.lps.identity.SensoryRecord#lastUpdate
     * @type jibo.animate.Time
     */
    public lastUpdate:Time;

    constructor(entity: LPSEntity, position:any, type:SensoryType, reportedTS: Time){
        // Get all of the info from LPS
        Object.assign(this, entity);
        this.type = type;

        // Additionally, have some convenience properties
        this.raw = entity;
        if(position !== null && position !== undefined){
            this.position = position;
        }

        this.id = entity.id;
        this.confidence = entity.confidence;
        this.receivedAt = Clock.currentTime();
        this.reportedTS =  reportedTS;
    }

    /**
     * @method jibo.lps.identity.SensoryRecord#update
     * @param entity {jibo.lps#LPSEntity}
     * @intdocs
     */
    update(entity: LPSEntity) {
        Object.assign(this, entity);

        this.position = new THREE.Vector3(entity.position.x, entity.position.y, entity.position.z);
        this.lastUpdate = Clock.currentTime();
    }

}

/**
 * @description
 * PresenceEvents that can be subscribed to. Used as a helper to `PresenceRecords`
 * in `DataConverter`.
 * @memberof jibo.lps.identity
 * @class PresenceEvents
 * @intdocs
 */
export class PresenceEvents extends EventContainer {

    /**
     * Fires upon transition from nobody being present to at least one person being present
     * in the robot's environment.
     * @name jibo.lps.identity.PresenceEvents#presenceStarted
     * @type {Event<any>}
     */
    public presenceStarted = new Event<any>("Presence Started");

    /**
     * Fires upon transition from at least one person being present to nobody being present
     * in the robot's environment.
     * @name jibo.lps.identity.PresenceEvents#presenceEnded
     * @type {Event<any>}
     */
    public presenceEnded = new Event<any>("Presence Ended");
    public constructor() {
        super();
    }
}

/**
 * @description
 * Record of any type of presence
 * @memberof jibo.lps.identity
 * @class PresenceRecord
 */
export class PresenceRecord {

    /**
     * @name jibo.lps.identity.PresenceRecord#name
     * @type {string}
     * @description Name (recognized ID) of present person.
     */
    public name:string;

    /**
     * @name jibo.lps.identity.PresenceRecord#kind
     * @description Kind of presence (`voice`, `motion`, etc).
     * @type jibo.lps.identity#SensoryType
     */
    public kind:SensoryType = null;

    /**
     * @name jibo.lps.identity.PresenceRecord#present
     * @description Whether or not presence is actively present around robot.
     * @type {Boolean}
     */
    public present:boolean;

    /**
     * @name jibo.lps.identity.PresenceRecord#confidence
     * @description Confidence in this presence.
     * @type {Number}
     */
    public confidence:number;

    /**
     * @name jibo.lps.identity.PresenceRecord#lastUpdate
     * @description Time presence was received.
     * @type {jibo.animate.Time}
     */
    public lastUpdate:Time;

    /**
     * @name jibo.lps.identity.PresenceRecord#events
     * @description Events on this particular presence.
     * @type {jibo.lps.identity.PresenceEvents}
     */
    public events = new PresenceEvents();

    constructor(presence){
        // Get all of the info from LPS
        Object.assign(this, presence);
        this.lastUpdate = Clock.currentTime();
    }

    /**
     * @method jibo.lps.identity.PresenceRecord#update
     * @param presence {jibo.lps.identity.PresenceRecord}
     * @intdocs
     */
    update(presence: PresenceRecord) {
        const presenceState = this.present;
        Object.assign(this, presence);
        // our presence state just changed!
        if(presenceState !== this.present) {
            //
            if(this.present === true) {
                this.events.presenceStarted.emit();
            }
            else {
                this.events.presenceEnded.emit();
            }
        }
        this.lastUpdate = Clock.currentTime();
    }
}


/**
 * @class SpeakerIdInfo
 * @memberof jibo.lps.identity
 * @description Information about the speaker ID.
 */
export class SpeakerIdInfo {

    /**
     * Looper ID, if recognized.
     * @name jibo.lps.identity.SpeakerIdInfo#id
     * @type {string}
     */
    id: string;

    /**
     * Confidence in the recognition.
     * @name jibo.lps.identity.SpeakerIdInfo#confidence
     * @type {number | jibo.gl#SpeakerIdConfidence}
     */
    confidence: number | SpeakerIdConfidence;

    constructor(info?:SpeakerIdInfo) {
        this.id = info ? info.id : "";
        this.confidence = info ? info.confidence : 0;
    }
}

/**
 * @description
 * Record of a Speaker ID or recent speaker recognition.
 * @memberof jibo.lps.identity
 * @class SpeakerRecord
 */
export class SpeakerRecord {

    /**
     * ID information about the speaker recognized.
     * @name jibo.lps.identity.SpeakerRecord#idInfo
     * @type {jibo.lps.identity.SpeakerIdInfo}
     */
    public idInfo: SpeakerIdInfo;

    /**
     * Confidence and position of location.
     * @name jibo.lps.identity.SpeakerRecord#location
     * @type {jibo.lps.ConfidencePosition}
     */
    public location:ConfidencePosition;

    /**
     * Matching entity ID ir -1 if not directly correlated to known entity.
     * @name jibo.lps.identity.SpeakerRecord#entity
     * @type {number}
     */
    public entity: number;

    constructor(speaker?:SpeakerRecord){
        this.idInfo = speaker ? speaker.idInfo : new SpeakerIdInfo();
        this.entity = speaker ? speaker.entity : -1;
        this.location = speaker ? speaker.location : null;
    }
}
