/*
 * These are definitions and classes that are shared by the ASR/GL code in the "Jibo" and "Skills-service-manager" packages.
 */

import uuid = require('uuid');

/**
 * @typedef jibo.gl#GlobalEventData
 * @description The payload format for the event {@link jibo.globalEvents#global}.
 * @prop name {string} The name of the global event in question.
 * @prop data {any} The data payload of the global event.
 */
export interface GlobalEventData {
    name: string;
    data: any;
}
/**
 * Enum of global commands.
 * @typedef GlobalCommand
 * @property SLEEP {any} "sleep"
 * @property HELP {any} "help"
 * @property STOP {any} "stop"
 * @property PAUSE {any} "pause"
 * @property VOLUME {any} "volume"
 * @property WHATCANIDO {any} "whatCanIDo"
 * @property HOLDON {any} "holdOn"
 * @intdocs
 */
export type GlobalCommand = 'SLEEP' |'HELP' |'STOP' |'PAUSE' |'VOLUME' | 'WHATCANIDO' | 'HOLDON';
export namespace GlobalCommand {
    export const SLEEP: GlobalCommand = 'SLEEP';
    export const HELP: GlobalCommand = 'HELP';
    export const STOP: GlobalCommand = 'STOP';
    export const PAUSE: GlobalCommand = 'PAUSE';
    export const VOLUME: GlobalCommand = 'VOLUME';
    export const WHATCANIDO: GlobalCommand = 'WHATCANIDO';
    export const HOLDON: GlobalCommand = 'HOLDON';
}

export const GlobalCommandMap = new Map<string, GlobalCommand>();
GlobalCommandMap.set("sleep", GlobalCommand.SLEEP);
GlobalCommandMap.set("help", GlobalCommand.HELP);
GlobalCommandMap.set("stop", GlobalCommand.STOP);
GlobalCommandMap.set("pause", GlobalCommand.PAUSE);
GlobalCommandMap.set("volume", GlobalCommand.VOLUME);
GlobalCommandMap.set("whatCanIDo", GlobalCommand.WHATCANIDO);
GlobalCommandMap.set("holdOn", GlobalCommand.HOLDON);

/**
 * @class NLUResponse
 * @description Structure of NLU Responses
 * @memberof jibo.gl
 */
export class NLUResponse {
    /**
     * Status of NLU response
     * @name jibo.gl.NLUResponse#Status
     * @type {jibo.gl.NLUResponse#REQ_STATUS}
     * @readOnly
     */
    Status:REQ_STATUS;
    /**
     * Message that may come along with NLU response. Different types for different statuses.
     * @name jibo.gl.NLUResponse#Message
     * @type {jibo.gl.NLUResponse#NLUMessages}
     * @readOnly
     */
    Message:NLUMessages;
    /**
     * Stats that may come back from NLU response
     * @name jibo.gl.NLUResponse#Stats
     * @type {Array<any>}
     * @readOnly
     */
    Stats:any[];
    /**
     * Rules names that may come back with NLU response
     * @name jibo.gl.NLUResponse#Rule_name
     * @type {Array<string>}
     * @readOnly
     */
    Rule_name:string[];
    /**
     * Array of rule versions that may come back with NLU response
     * @name jibo.gl.NLUResponse#Rule_version
     * @type {Array<string>}
     * @readOnly
     */
    Rule_version:string[];
    /**
     * Results of NLU Parse
     * @name jibo.gl.NLUResponse#Result
     * @type {Array<jibo.gl.ParseResults>}
     * @readOnly
     */
    Result: ParseResults[];
    /**
     * URI that may come back with NLU response
     * @name jibo.gl.NLUResponse#URI
     * @type {string}
     * @readOnly
     */
    URI: string;
}

/**
 * Enum of request statuses returned from NLU.
 * @typedef jibo.gl.NLUResponse#REQ_STATUS
 * @property OK {String} Request status is ok.
 * @property ERROR {String} Request has error response.
 */
export enum REQ_STATUS {
    OK = <any>'OK',
    ERROR = <any>'ERROR'
};

export type Callback = (err?: any, res?: any) => void;

/**
 * Enum of possible messages from NLU Service.
 * @typedef jibo.gl.NLUResponse#NLUMessages
 * @property RESET_MEMORY {any} "NLU_EXECUTED_RESET_MEMORY"
 */
export enum NLUMessages {
    RESET_MEMORY = <any> "NLU_EXECUTED_RESET_MEMORY"
};

/**
 * @class ListenOptions
 * @description Options to be used for listening.
 * @memberof jibo.gl
 */
export class ListenOptions {

    /**
     * Listen for incremental results.
     * @name jibo.gl.ListenOptions#incremental
     * @type {boolean}
     */
    incremental:boolean;

    /**
     * Parse the incremental results (with given grammar).
     * @name jibo.gl.ListenOptions#parseIncremental
     * @type {boolean}
     */
    parseIncremental:boolean;

    /**
     * Listen for speech-to-text (cloud) results.
     * @name jibo.gl.ListenOptions#speech_to_text
     * @type {boolean}
     */
    speech_to_text:boolean;

    /**
     * Listen for "Hey Jibo" before phrase.
     * @name jibo.gl.ListenOptions#hotphrase
     * @type {String}
     */
    hotphrase:string;

    /**
     * Verbose SSM and jibo logging within listener
     * @name jibo.gl.ListenOptions#verbose
     * @type {boolean}
     */
    verbose:boolean;

    /**
     * Language option for ASR recognition.
     * @name jibo.gl.ListenOptions#language
     * @type {string}
     */
    language: string;

    /**
     * Force a Non "Hey Jibo" (empty hotphrase) listener to parse the global and launch grammars
     * @name jibo.gl.ListenOptions#forceGlobal
     * @type {boolean}
     * @intdocs
     */
    forceGlobal:boolean;

    /**
     * Expected duration of the utterance. 'short', 'medium', 'long', 'infinite'.
     * Infinite `expectedDuration` must be stopped manually.
     * @name jibo.gl.ListenOptions#expectedDuration
     * @type {string}
     */
    expectedDuration: string;

    /**
     * Parse all ASR results instead of only the best one (with given rule).
     * @name jibo.gl.ListenOptions#parseAllASR
     * @type {boolean}
     */
    parseAllASR:boolean;

    /**
     * Any metadata the skill wishes to provide for ASR Service debugging.
     * @name jibo.gl.ListenOptions#metadata
     * @type {any}
     * @intdocs
     */
    metadata: any;

    constructor(options?:any) {
        this.hotphrase = options ? options.hotphrase : "";
        this.speech_to_text = options ? options.speech_to_text : false;
        this.parseIncremental = options ? options.parseIncremental : false;
        this.incremental = options ? options.incremental : false;
        this.language = options ? options.language : 'en-US';
        this.verbose = options ? options.verbose : false;
        this.forceGlobal = options ? !!options.forceGlobal : false;
        this.expectedDuration = options ? options.expectedDuration : 'medium';

        this.parseAllASR = options ? options.parseAllASR : false;
        this.metadata = options ? options.metadata : null;
    }
}

/**
 * @class ParseResults
 * @memberof jibo.gl
 * @description Results of an NLParse
 */
export class ParseResults {

    /**
     * Raw text input to NLParse
     * @name jibo.gl.ParseResults#Input
     * @type {String}
     * @readOnly
     */
    Input:string;

    /**
     * NLParse according to given parse rule
     * @name jibo.gl.ParseResults#NLParse
     * @type {any}
     * @readOnly
     */
    NLParse:any;

    /**
     * LaunchParse according to given parse rule
     * @name jibo.gl.ParseResults#launchParse
     * @type {any}
     * @readOnly
     */
    launchParse: any;
    /**
     * Score for how well the text input parsed against the rule.
     * @name jibo.gl.ParseResults#heuristic_score
     * @type {Number}
     * @readOnly
     */
    heuristic_score:number;

    /**
     * @name jibo.gl.ParseResults#status
     * @type {String}
     * @readOnly
     */
    status: string;

    constructor(Input?:string, NLParse?:any, launchParse?:any, heuristic_score?:number) {

        this.Input = Input || "";
        this.NLParse = NLParse;
        this.launchParse = launchParse;
        this.heuristic_score = heuristic_score ? heuristic_score : 0;
    }
}
/**
 * @class NoMatchResults
 * @memberof jibo.gl
 * @description Results of a NoMatch event
 */
export class NoMatchResults extends ParseResults {
    /**
     * Whether or not these parse results won against launch or global
     * @name jibo.gl.NoMatchResults#triggeredByHJ
     * @type {Boolean}
     * @readOnly
     */
    triggeredByHJ: boolean;

    constructor(parse:ParseResults, triggeredByHJ:boolean) {
        super(parse.Input, parse.NLParse, parse.launchParse, parse.heuristic_score);
        this.triggeredByHJ = triggeredByHJ;
    }
}

/**
 * @class Utterance
 * @description Utterance object from ASR result.
 * @memberof jibo.gl
 */
export class Utterance {

    /**
     * Utterance heard from ASR.
     * @name jibo.gl.Utterance#utterance
     * @type {Number}
     */
    public utterance: string;

    /**
     * Score for how confident this is what was spoken.
     * @name jibo.gl.Utterance#score
     * @type {Number}
     */
    public score: number;

    constructor(options: {utterance:string, score?:number}) {
        this.utterance = options.utterance || "";
        this.score = options.score || 0;
    }
}

/**
 * @class ListenResults
 * @description Results of a listener.
 * @memberof jibo.gl
 */
export class ListenResults {

    /**
     * Parsed results of the listen
     * @name jibo.gl.ListenResults#result
     * @type {jibo.gl.ParseResults}
     * @readOnly
     */
    result: ParseResults;

    /**
     * Other possible results of ASR.
     * @name jibo.gl.ListenResults#otherResults
     * @type {Array<jibo.gl.Utterance>}
     * @readOnly
     */
    otherResults: Utterance[];
    /**
     * The ID of the audio action in ASR Service which gave these results
     * @name jibo.gl.ListenResults#audioActionId
     * @type {string}
     * @readOnly
     */
    audioActionId:string;
    constructor(input?:Utterance, parse?:ParseResults, otherResults?:Utterance[], id?:string) {
        if(!input) {
            input = {
                utterance: "",
                score: 0
            };
        }
        this.result = parse || new ParseResults(input.utterance);
        this.otherResults = otherResults || [];
        this.audioActionId = id || "";
    }
}

/**
 * @class PronunciationOptions
 * @description Options to pronounce.
 * @memberof jibo.gl
 */
export class PronunciationOptions extends ListenOptions {

    /**
     * Word to pronounce.
     * @name jibo.gl.PronunciationOptions#word
     * @type {string}
     * @readOnly
     */
    word: string;

    /**
     * listenerId of the pronounciation listener.
     * @name jibo.gl.PronunciationOptions#listenerId
     * @type {string}
     * @readOnly
     */
    listenerId: string;

    /**
     * Verbose to provide useful debug informatino in SSM.
     * @name jibo.gl.PronunciationOptions#verbose
     * @type {boolean}
     * @readOnly
     */
    verbose: boolean;

    /**
     * Automatically collect acoustic example after generating g2p model.
     * @name jibo.gl.PronunciationOptions#collectExample
     * @type {boolean}
     * @readOnly
     */
    collectExample: boolean;

    /**
     * Pronunciation listener action to perform.
     * @name jibo.gl.PronunciationOptions#action
     * @type {string}
     * @readOnly
     */
    action: string;

    constructor(word?:string, listenerId?:string, verbose?:boolean, collectExample?:boolean) {
        super();

        this.word = word || "";
        this.listenerId = listenerId || uuid.v1();
        this.verbose = verbose || false;
        this.collectExample = collectExample || true;
    }
}

export class ASRRequestOptions {
    public authenticateSpeaker: string;
    public bargein: string;
    public detectEnd: boolean;
    public expectedDuration: string;
    public heyJibo: boolean;
    public incremental: boolean;
    public metadata: any;
    public nbest: number;
    public parseFinal: boolean;
    public parseIncremental: boolean;
    public precompiledHandle: string;
    public speech_to_text: boolean;
    public hotphrase:string;
    public language: string;
    public known_speaker_id:string;

    constructor(options:any) {
        if(!options) {
            options = {};
        }
        this.authenticateSpeaker = options.authenticateSpeaker;
        this.bargein = options.bargein;
        this.detectEnd = options.detectEnd;
        this.expectedDuration = options.expectedDruation;
        this.heyJibo = options.heyJibo;
        this.incremental = options.incremental;
        this.metadata = options.metadata;
        this.nbest = options.nbest;
        this.parseFinal = options.parseFinal;
        this.parseIncremental = options.parseIncremental;
        this.precompiledHandle = options.precompiledHandle;
        this.speech_to_text = options.speech_to_text;
        this.hotphrase = options.hotphrase;
        this.language = options.language;
        this.known_speaker_id = options.known_speaker_id;
    }
}

