/**
 * @class SpeakerId
 * @description Structure of SpeakerId
 * @memberof jibo.gl
 */
export class SpeakerId {

   /**
    * Status of Speaker ID response.
    * @name jibo.gl.SpeakerId#status
    * @type {string}
    * @readOnly
    */
    // "speaker_id_status" was previously "status" in skill service manager version
    status:string = "";

   /**
    * Array of Speaker IDs in listen results
    * @name jibo.gl.SpeakerId#speakers
    * @type {Array}
    * @readOnly
    */
    // "speaker_ids" was originally "speakers" in skill service manager version
    speakers:Speaker[] = [];
    constructor(speakerId?:any) {
        this.speakers = speakerId ? speakerId.speakers : [new Speaker()];
        this.status = speakerId ? speakerId.status :SpeakerIdStatus.NOT_USED;
        // data format we receive from ASR
        if(speakerId && speakerId.speaker_ids) {
            this.speakers = speakerId.speaker_ids;
            this.status = speakerId.speaker_id_status;
        }
    }
}

/**
 * @class Speaker
 * @description One speaker object from SpeakerIds
 * @memberof jibo.gl
 */
export class Speaker {

   /**
    * ID of speaker returned in listen results
    * @name jibo.gl.Speaker#speaker_id
    * @type {string}
    * @readOnly
    */
    speaker_id:string = "";

   /**
    * Confidence of `speaker_id` returned in listen results
    * @name jibo.gl.Speaker#score
    * @type {number}
    * @readOnly
    */
    score:number = 0;
    constructor(speaker?:string, score?:number) {
        this.speaker_id = speaker || "";
        this.score = score || 0;
    }
}



