/**
 * Enum of Speaker ID Statuses
 * @typedef jibo.gl#SID_Status
 * @property ACCEPTED {String} "ACCEPTED"
 * @property NOT_USED {String} "NOT-USED"
 * @property REJECTED {String} "REJECTED"
 * @property ID_TI_NOT_AVAILABLE {String} "ID-TI-NOT-AVAILABLE"
 */
export enum SID_Status {
    ACCEPTED = <any> 'ACCEPTED',
    NOT_USED = <any> 'NOT-USED',
    REJECTED = <any> 'REJECTED',
    ID_TI_NOT_AVAILABLE = <any> 'ID-TI-NOT-AVAILABLE'
};

/**
 * @class IndividualSpeaker
 * @description One speaker object from SpeakerIds
 * @memberof jibo.gl
 */
export class IndividualSpeaker {
    /**
     * ID of speaker returned in listen results
     * @name jibo.gl.IndividualSpeaker#ID
     * @type {string}
     * @readOnly
     */
    ID:string = "";
    /**
     * Score of `speaker_id` returned in listen results
     * @name jibo.gl.IndividualSpeaker#Score
     * @type {number}
     * @readOnly
     */
    Score:number = 0;
    /**
     * Status of `speaker_id` returned in listen results
     * @name jibo.gl.IndividualSpeaker#SID_Status
     * @type {jibo.gl#SID_Status}
     * @readOnly
     */
    SID_Status: SID_Status;
    /**
     * Confidence of `speaker_id` returned in listen results
     * @name jibo.gl.IndividualSpeaker#SID_Confidence
     * @type {number}
     * @readOnly
     */
    SID_Confidence:number = 0;
    /**
     * ID of speaker returned in listen results. Could be either from ASR Service.
     * @name jibo.gl.IndividualSpeaker#id
     * @type {string}
     * @readOnly
     */
    id:string = "";
    /**
     * Score of `speaker_id` returned in listen results. Could be either from ASR Service.
     * @name jibo.gl.IndividualSpeaker#score
     * @type {number}
     * @readOnly
     */
    score:number = 0;
    /**
     * Status of `speaker_id` returned in listen results. Could be either from ASR Service.
     * @name jibo.gl.IndividualSpeaker#sid_status
     * @type {jibo.gl#SID_Status}
     * @readOnly
     */
    sid_status: SID_Status;
    /**
     * Confidence of `speaker_id` returned in listen results. Could be either from ASR Service.
     * @name jibo.gl.IndividualSpeaker#sid_confidence
     * @type {number}
     * @readOnly
     */
    sid_confidence:number = 0;
    constructor(speaker?: IndividualSpeaker) {
        (<any>Object).assign(this, speaker);
        // convert all the old way to the new way.
        this.id = this.id || this.ID;
        this.score = this.score || this.Score;
        this.sid_status = this.sid_status || this.SID_Status;
        this.sid_confidence = this.sid_confidence || this.SID_Confidence;
    }
}
